function escHtml(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
window.reviewUnmatched = function () {
  appsmith.triggerEvent('onOpenUnmatchedReview');
};
function render(model) {
  const rows = model.assets || [];
  const tbody = document.getElementById('assetsBody');
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty-state">No assets booked yet</td></tr>';
    return;
  }
  tbody.innerHTML = rows.map(function (r) {
    const badge = r.needs_review ? '<span class="badge-review">Unmatched</span>' : '<span class="badge-matched">Matched</span>';
    const dataPill = r.data_bearing ? '<span class="data-pill data-yes">Yes</span>' : '<span class="data-pill data-no">No</span>';
    return '<tr>' + '<td>' + badge + '</td>' + '<td><a class="barcode-link" data-asset-id="' + r.asset_id + '">' + escHtml(r.asset_ref) + '</a></td>' + '<td>' + escHtml(r.item_type || '—') + '</td>' + '<td>' + escHtml(r.make || '—') + '</td>' + '<td>' + escHtml(r.model || '—') + '</td>' + '<td><input type="text" class="serial-input" data-asset-id="' + r.asset_id + '" value="' + escHtml(r.serial_number || '') + '" placeholder="Enter serial..." /></td>' + '<td>' + dataPill + '</td>' + '</tr>';
  }).join('');
  document.querySelectorAll('.barcode-link').forEach(function (el) {
    el.addEventListener('click', function () {
      appsmith.updateModel({
        selectedAssetId: Number(this.dataset.assetId)
      });
      appsmith.triggerEvent('onViewAsset');
    });
  });
  document.querySelectorAll('.serial-input').forEach(function (input) {
    var originalValue = input.value;
    input.addEventListener('blur', function () {
      var newValue = this.value.trim();
      if (newValue === originalValue) return;
      appsmith.updateModel({
        editedAssetId: Number(this.dataset.assetId),
        editedSerial: newValue
      });
      appsmith.triggerEvent('onSerialEdited');
      originalValue = newValue;
    });
    input.addEventListener('keydown', function (e) {
      if (e.key === 'Enter') this.blur();
    });
  });
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function () {
    render(appsmith.model);
  });
  appsmith.onModelChange(function (model) {
    render(model);
  });
}
initWhenReady();

